medium text-white hover:bg-destructive/90" type="submit"><svg aria-hidden="true" class="size-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M3 6h18M8 6V4h8v2M19 6l-1 15H6L5 6M10 11v6M14 11v6"/></svg>Delete</button></form></div></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?>
